use image::RgbaImage;
use serde::Serialize;
use std::collections::{HashSet, VecDeque};
use std::env;
use std::fs;
use std::path::{Path, PathBuf};

#[derive(Clone, Copy, Debug, Serialize)]
struct Point {
    x: f32,
    y: f32,
}

#[derive(Clone, Copy, Debug, Serialize)]
struct BBox {
    x0: u32,
    y0: u32,
    x1: u32,
    y1: u32,
}

#[derive(Clone, Debug, Serialize)]
struct PhyleRenderUnit {
    id: u32,
    depth: u8,
    carrier: &'static str,
    lean_basis: &'static str,
    role: String,
    render_faces: Vec<[Point; 3]>,
    coverage: f32,
}

#[derive(Clone, Debug, Serialize)]
struct BuleyeanHypothesis {
    name: String,
    rejection_mass: f32,
    probability: f32,
}

#[derive(Clone, Debug, Serialize)]
struct BayesianClassifierNode {
    component_id: u32,
    bbox: BBox,
    base: Point,
    root: Point,
    posterior: Vec<BuleyeanHypothesis>,
    decision: String,
    cells: Vec<PhyleRenderUnit>,
    children: Vec<BayesianClassifierNode>,
}

#[derive(Clone, Debug, Serialize)]
struct SolvedBody {
    source: String,
    width: u32,
    height: u32,
    bbox: BBox,
    base: Point,
    root: Point,
    classifier_tree: BayesianClassifierNode,
    phyle_cells: Vec<PhyleRenderUnit>,
}

#[derive(Clone, Debug)]
struct Args {
    input: PathBuf,
    out_dir: PathBuf,
    limit: Option<usize>,
    max_depth: u8,
    min_coverage: f32,
}

fn main() -> Result<(), String> {
    let args = parse_args()?;
    fs::create_dir_all(&args.out_dir).map_err(|e| e.to_string())?;

    let mut images = collect_images(&args.input)?;
    images.sort();
    if let Some(limit) = args.limit {
        images.truncate(limit);
    }

    let mut solved = 0usize;
    for image_path in images {
        match solve_image(&image_path, args.max_depth, args.min_coverage) {
            Ok(body) => {
                let stem = image_path
                    .file_stem()
                    .and_then(|s| s.to_str())
                    .unwrap_or("image")
                    .replace(' ', "-");
                let json_path = args.out_dir.join(format!("{stem}.phyle-fractal.json"));
                let svg_path = args.out_dir.join(format!("{stem}.phyle-fractal.svg"));
                let ply_path = args.out_dir.join(format!("{stem}.phyle-fractal.ply"));
                fs::write(
                    &json_path,
                    serde_json::to_string_pretty(&body).map_err(|e| e.to_string())?,
                )
                .map_err(|e| e.to_string())?;
                fs::write(&svg_path, render_svg(&body)).map_err(|e| e.to_string())?;
                fs::write(&ply_path, render_ply(&body)).map_err(|e| e.to_string())?;
                println!(
                    "solved={} cells={} ply={} svg={}",
                    image_path.display(),
                    body.phyle_cells.len(),
                    ply_path.display(),
                    svg_path.display()
                );
                solved += 1;
            }
            Err(err) => {
                eprintln!("skip={} reason={}", image_path.display(), err);
            }
        }
    }

    println!("solved_images={solved}");
    println!("out_dir={}", args.out_dir.display());
    Ok(())
}

fn parse_args() -> Result<Args, String> {
    let args: Vec<String> = env::args().skip(1).collect();
    let get = |flag: &str| -> Option<String> {
        args.iter()
            .position(|a| a == flag)
            .and_then(|p| args.get(p + 1))
            .cloned()
    };
    Ok(Args {
        input: PathBuf::from(get("--input").ok_or("--input required")?),
        out_dir: PathBuf::from(
            get("--out").unwrap_or_else(|| ".qa-artifacts/phyle-fractal".into()),
        ),
        limit: get("--limit").and_then(|v| v.parse().ok()),
        max_depth: get("--max-depth").and_then(|v| v.parse().ok()).unwrap_or(7),
        min_coverage: get("--min-coverage")
            .and_then(|v| v.parse().ok())
            .unwrap_or(0.18),
    })
}

fn collect_images(input: &Path) -> Result<Vec<PathBuf>, String> {
    if input.is_file() {
        return Ok(vec![input.to_path_buf()]);
    }
    let mut out = Vec::new();
    for entry in fs::read_dir(input).map_err(|e| e.to_string())? {
        let path = entry.map_err(|e| e.to_string())?.path();
        if !path.is_file() {
            continue;
        }
        let ext = path
            .extension()
            .and_then(|e| e.to_str())
            .unwrap_or("")
            .to_ascii_lowercase();
        if matches!(ext.as_str(), "jpg" | "jpeg" | "png" | "webp") {
            out.push(path);
        }
    }
    Ok(out)
}

fn solve_image(path: &Path, max_depth: u8, min_coverage: f32) -> Result<SolvedBody, String> {
    let image = image::open(path)
        .map_err(|e| format!("decode: {e}"))?
        .resize(720, 720, image::imageops::FilterType::Triangle)
        .to_rgba8();
    let (width, height) = image.dimensions();
    let mask = foreground_mask(&image);
    let component = largest_component(&mask, width, height).ok_or("no body mask found")?;
    let bbox = bbox_for_component(&component, width);
    let base = base_point(&component, width);
    let root = Point {
        x: (bbox.x0 + bbox.x1) as f32 * 0.5,
        y: bbox.y0 as f32,
    };

    let mut next_cell_id = 0_u32;
    let mut next_component_id = 0_u32;
    let classifier_tree = solve_classifier_node(
        component,
        width,
        height,
        max_depth,
        min_coverage,
        &mut next_cell_id,
        &mut next_component_id,
    );
    let mut cells = Vec::new();
    collect_cells(&classifier_tree, &mut cells);

    Ok(SolvedBody {
        source: path.display().to_string(),
        width,
        height,
        bbox,
        base,
        root,
        classifier_tree,
        phyle_cells: cells,
    })
}

fn solve_classifier_node(
    component: HashSet<usize>,
    width: u32,
    height: u32,
    max_depth: u8,
    min_coverage: f32,
    next_cell_id: &mut u32,
    next_component_id: &mut u32,
) -> BayesianClassifierNode {
    let component_id = *next_component_id;
    *next_component_id += 1;
    let bbox = bbox_for_component(&component, width);
    let base = base_point(&component, width);
    let root = Point {
        x: (bbox.x0 + bbox.x1) as f32 * 0.5,
        y: bbox.y0 as f32,
    };
    let mut cells = Vec::new();
    let mut filled = HashSet::new();
    grow_fern_phyle(
        base,
        root,
        bbox,
        max_depth,
        min_coverage,
        &component,
        &mut filled,
        width,
        height,
        next_cell_id,
        &mut cells,
    );
    let component_area = component.len().max(1) as f32;
    let covered_area = cells
        .iter()
        .flat_map(|cell| {
            cell.render_faces
                .iter()
                .map(|face| triangle_area(*face) * cell.coverage)
        })
        .sum::<f32>();
    let coverage_ratio = (covered_area / component_area).clamp(0.0, 2.0);
    let cell_pressure = (cells.len() as f32 / 180.0).min(2.0);
    let split_components = split_component_by_vertical_valleys(&component, width, bbox);
    let split_gain = split_components
        .as_ref()
        .map(|parts| parts.len() as f32 * 0.18)
        .unwrap_or(0.0);
    let single_rejection = (1.0 - coverage_ratio.min(1.0)) * 5.0 + cell_pressure;
    let split_rejection = if split_components.is_some() {
        2.3 - split_gain + coverage_ratio.min(1.0)
    } else {
        4.0 + coverage_ratio.min(1.0)
    };
    let posterior = buleyean_posterior([
        ("single_phyle_body", single_rejection),
        ("component_split", split_rejection),
    ]);
    let split_probability = posterior
        .iter()
        .find(|h| h.name == "component_split")
        .map(|h| h.probability)
        .unwrap_or(0.0);
    let should_split = split_probability > 0.58 && bbox.x1.saturating_sub(bbox.x0) > 36;
    let children = if should_split {
        split_components
            .unwrap_or_default()
            .into_iter()
            .filter(|part| part.len() > 64)
            .map(|part| {
                solve_classifier_node(
                    part,
                    width,
                    height,
                    max_depth.saturating_sub(1).max(3),
                    min_coverage,
                    next_cell_id,
                    next_component_id,
                )
            })
            .collect()
    } else {
        Vec::new()
    };
    let decision = if children.is_empty() {
        "single_phyle_body".to_string()
    } else {
        "component_split".to_string()
    };
    BayesianClassifierNode {
        component_id,
        bbox,
        base,
        root,
        posterior,
        decision,
        cells,
        children,
    }
}

fn buleyean_posterior<const N: usize>(hypotheses: [(&str, f32); N]) -> Vec<BuleyeanHypothesis> {
    let total_rejection = hypotheses
        .iter()
        .map(|(_, rejection)| rejection.max(0.0))
        .sum::<f32>();
    let weights: Vec<f32> = hypotheses
        .iter()
        .map(|(_, rejection)| (total_rejection - rejection.max(0.0) + 1.0).max(1e-6))
        .collect();
    let total_weight = weights.iter().sum::<f32>().max(1e-6);
    hypotheses
        .iter()
        .zip(weights)
        .map(|((name, rejection_mass), weight)| BuleyeanHypothesis {
            name: (*name).to_string(),
            rejection_mass: rejection_mass.max(0.0),
            probability: weight / total_weight,
        })
        .collect()
}

fn split_component_by_vertical_valleys(
    component: &HashSet<usize>,
    width: u32,
    bbox: BBox,
) -> Option<Vec<HashSet<usize>>> {
    let w = bbox.x1.saturating_sub(bbox.x0).saturating_add(1);
    if w < 48 {
        return None;
    }
    let mut column_counts = vec![0_u32; w as usize];
    for &idx in component {
        let x = idx as u32 % width;
        if x >= bbox.x0 && x <= bbox.x1 {
            column_counts[(x - bbox.x0) as usize] += 1;
        }
    }
    let max_count = column_counts.iter().copied().max().unwrap_or(1);
    let valley_threshold = (max_count as f32 * 0.16).max(2.0) as u32;
    let mut cuts = Vec::new();
    for x in 4..w.saturating_sub(4) {
        let c = column_counts[x as usize];
        let left = column_counts[x.saturating_sub(4) as usize];
        let right = column_counts[(x + 4).min(w - 1) as usize];
        if c <= valley_threshold && left > c.saturating_mul(2) && right > c.saturating_mul(2) {
            cuts.push(bbox.x0 + x);
        }
    }
    if cuts.is_empty() {
        return None;
    }
    let mut ranges = Vec::new();
    let mut start = bbox.x0;
    for cut in cuts.into_iter().step_by(8) {
        if cut > start + 12 {
            ranges.push((start, cut));
            start = cut + 1;
        }
    }
    if bbox.x1 > start + 12 {
        ranges.push((start, bbox.x1));
    }
    if ranges.len() < 2 {
        return None;
    }
    let parts: Vec<HashSet<usize>> = ranges
        .into_iter()
        .map(|(x0, x1)| {
            component
                .iter()
                .copied()
                .filter(|idx| {
                    let x = *idx as u32 % width;
                    x >= x0 && x <= x1
                })
                .collect()
        })
        .filter(|part: &HashSet<usize>| part.len() > 64)
        .collect();
    if parts.len() < 2 {
        None
    } else {
        Some(parts)
    }
}

fn collect_cells(node: &BayesianClassifierNode, out: &mut Vec<PhyleRenderUnit>) {
    if node.children.is_empty() {
        out.extend(node.cells.iter().cloned());
        return;
    }
    for child in &node.children {
        collect_cells(child, out);
    }
}

fn foreground_mask(image: &RgbaImage) -> Vec<bool> {
    let (width, height) = image.dimensions();
    let mut lumas = Vec::with_capacity((width * height) as usize);
    for p in image.pixels() {
        let l = 0.2126 * p[0] as f32 + 0.7152 * p[1] as f32 + 0.0722 * p[2] as f32;
        let green = p[1] as f32 - p[0].max(p[2]) as f32;
        lumas.push((l, green));
    }
    let mean = lumas.iter().map(|(l, _)| *l).sum::<f32>() / lumas.len().max(1) as f32;
    lumas
        .iter()
        .map(|(l, green)| *l < mean * 0.88 || (*green > 6.0 && *l < mean * 1.08))
        .collect()
}

fn largest_component(mask: &[bool], width: u32, height: u32) -> Option<HashSet<usize>> {
    let mut seen = vec![false; mask.len()];
    let mut best = HashSet::new();
    for idx in 0..mask.len() {
        if seen[idx] || !mask[idx] {
            continue;
        }
        let mut comp = HashSet::new();
        let mut q = VecDeque::from([idx]);
        seen[idx] = true;
        while let Some(i) = q.pop_front() {
            comp.insert(i);
            let x = (i as u32) % width;
            let y = (i as u32) / width;
            for (nx, ny) in neighbors4(x, y, width, height) {
                let ni = (ny * width + nx) as usize;
                if !seen[ni] && mask[ni] {
                    seen[ni] = true;
                    q.push_back(ni);
                }
            }
        }
        if comp.len() > best.len() {
            best = comp;
        }
    }
    if best.is_empty() {
        None
    } else {
        Some(best)
    }
}

fn neighbors4(x: u32, y: u32, width: u32, height: u32) -> Vec<(u32, u32)> {
    let mut out = Vec::with_capacity(4);
    if x > 0 {
        out.push((x - 1, y));
    }
    if y > 0 {
        out.push((x, y - 1));
    }
    if x + 1 < width {
        out.push((x + 1, y));
    }
    if y + 1 < height {
        out.push((x, y + 1));
    }
    out
}

fn bbox_for_component(component: &HashSet<usize>, width: u32) -> BBox {
    let mut x0 = u32::MAX;
    let mut y0 = u32::MAX;
    let mut x1 = 0;
    let mut y1 = 0;
    for &idx in component {
        let x = idx as u32 % width;
        let y = idx as u32 / width;
        x0 = x0.min(x);
        y0 = y0.min(y);
        x1 = x1.max(x);
        y1 = y1.max(y);
    }
    BBox { x0, y0, x1, y1 }
}

fn base_point(component: &HashSet<usize>, width: u32) -> Point {
    let max_y = component
        .iter()
        .map(|idx| *idx as u32 / width)
        .max()
        .unwrap_or(0);
    let mut xs = Vec::new();
    for &idx in component {
        let y = idx as u32 / width;
        if max_y.saturating_sub(y) <= 3 {
            xs.push(idx as u32 % width);
        }
    }
    let x = if xs.is_empty() {
        0.0
    } else {
        xs.iter().sum::<u32>() as f32 / xs.len() as f32
    };
    Point { x, y: max_y as f32 }
}

fn grow_fern_phyle(
    base: Point,
    root: Point,
    bbox: BBox,
    max_depth: u8,
    min_coverage: f32,
    mask: &HashSet<usize>,
    filled: &mut HashSet<usize>,
    width: u32,
    height: u32,
    next_cell_id: &mut u32,
    out: &mut Vec<PhyleRenderUnit>,
) {
    let axis = Point {
        x: root.x - base.x,
        y: root.y - base.y,
    };
    let levels = max_depth.max(3);
    let body_width = bbox.x1.saturating_sub(bbox.x0).max(1) as f32;
    for level in 0..=levels {
        let t0 = level as f32 / (levels + 1) as f32;
        let t1 = (level + 1) as f32 / (levels + 1) as f32;
        let p0 = lerp(base, root, t0);
        let p1 = lerp(base, root, t1);
        let radius = body_width * 0.42 * (1.0 - t0).powf(0.72) + body_width * 0.035;
        let left = Point {
            x: p1.x - radius,
            y: p1.y + axis.y.abs() * 0.025,
        };
        let right = Point {
            x: p1.x + radius,
            y: p1.y + axis.y.abs() * 0.025,
        };
        push_if_admitted(
            [p0, left, p1],
            level,
            "left_frond",
            min_coverage,
            mask,
            filled,
            width,
            height,
            next_cell_id,
            out,
        );
        push_if_admitted(
            [p0, p1, right],
            level,
            "right_frond",
            min_coverage,
            mask,
            filled,
            width,
            height,
            next_cell_id,
            out,
        );
        let spine_width = (radius * 0.18).max(2.0);
        push_if_admitted(
            [
                Point {
                    x: p0.x - spine_width,
                    y: p0.y,
                },
                Point {
                    x: p0.x + spine_width,
                    y: p0.y,
                },
                p1,
            ],
            level,
            "spine",
            min_coverage * 0.5,
            mask,
            filled,
            width,
            height,
            next_cell_id,
            out,
        );
        if level < levels {
            let child_depth = (level + 1).min(levels);
            let frond_root_l = Point {
                x: p1.x - radius,
                y: p1.y + radius * 0.18,
            };
            let frond_root_r = Point {
                x: p1.x + radius,
                y: p1.y + radius * 0.18,
            };
            grow_frond(
                p1,
                frond_root_l,
                child_depth,
                levels,
                min_coverage,
                mask,
                filled,
                width,
                height,
                next_cell_id,
                out,
            );
            grow_frond(
                p1,
                frond_root_r,
                child_depth,
                levels,
                min_coverage,
                mask,
                filled,
                width,
                height,
                next_cell_id,
                out,
            );
        }
    }

    let mut frontier = frontier_points(mask, filled, width, bbox);
    frontier.sort_by(|a, b| {
        let da = distance2(*a, base);
        let db = distance2(*b, base);
        da.partial_cmp(&db).unwrap_or(std::cmp::Ordering::Equal)
    });
    for target in frontier.into_iter().take(512) {
        let seed = nearest_filled_or_base(target, filled, width, base);
        unfold_to_mass(
            seed,
            target,
            0,
            max_depth.saturating_add(4),
            min_coverage,
            mask,
            filled,
            width,
            height,
            next_cell_id,
            out,
        );
    }
}

fn grow_frond(
    seed: Point,
    tip: Point,
    depth: u8,
    max_depth: u8,
    min_coverage: f32,
    mask: &HashSet<usize>,
    filled: &mut HashSet<usize>,
    width: u32,
    height: u32,
    next_cell_id: &mut u32,
    out: &mut Vec<PhyleRenderUnit>,
) {
    if depth >= max_depth {
        return;
    }
    let midp = lerp(seed, tip, 0.62);
    let dx = tip.x - seed.x;
    let dy = tip.y - seed.y;
    let curl = Point {
        x: midp.x - dy * 0.12,
        y: midp.y + dx * 0.08,
    };
    push_if_admitted(
        [seed, curl, tip],
        depth,
        "recursive_frond",
        min_coverage,
        mask,
        filled,
        width,
        height,
        next_cell_id,
        out,
    );
    let next_tip = Point {
        x: tip.x + dx * 0.34,
        y: tip.y + dy * 0.28,
    };
    grow_frond(
        tip,
        next_tip,
        depth + 1,
        max_depth,
        min_coverage,
        mask,
        filled,
        width,
        height,
        next_cell_id,
        out,
    );
}

fn unfold_to_mass(
    seed: Point,
    target: Point,
    depth: u8,
    max_depth: u8,
    min_coverage: f32,
    mask: &HashSet<usize>,
    filled: &mut HashSet<usize>,
    width: u32,
    height: u32,
    next_cell_id: &mut u32,
    out: &mut Vec<PhyleRenderUnit>,
) {
    if depth >= max_depth || distance2(seed, target) < 9.0 {
        return;
    }
    let midp = lerp(seed, target, 0.55);
    let dx = target.x - seed.x;
    let dy = target.y - seed.y;
    let spread = (dx * dx + dy * dy).sqrt().max(1.0) * 0.12;
    let normal = Point {
        x: -dy / (dx * dx + dy * dy).sqrt().max(1.0),
        y: dx / (dx * dx + dy * dy).sqrt().max(1.0),
    };
    let wing = Point {
        x: midp.x + normal.x * spread,
        y: midp.y + normal.y * spread,
    };
    let before = filled.len();
    push_if_admitted(
        [seed, wing, target],
        depth,
        "mass_unfold",
        min_coverage * 0.55,
        mask,
        filled,
        width,
        height,
        next_cell_id,
        out,
    );
    if filled.len() == before {
        return;
    }
    let next_target = Point {
        x: target.x + dx * 0.18,
        y: target.y + dy * 0.18,
    };
    unfold_to_mass(
        target,
        next_target,
        depth + 1,
        max_depth,
        min_coverage,
        mask,
        filled,
        width,
        height,
        next_cell_id,
        out,
    );
}

fn push_if_admitted(
    tri: [Point; 3],
    depth: u8,
    role: &str,
    min_coverage: f32,
    mask: &HashSet<usize>,
    filled: &mut HashSet<usize>,
    width: u32,
    height: u32,
    next_cell_id: &mut u32,
    out: &mut Vec<PhyleRenderUnit>,
) {
    let coverage = triangle_coverage(tri, mask, width, height);
    let pixels = triangle_mask_pixels(tri, width, height);
    let new_hits = pixels
        .iter()
        .filter(|idx| mask.contains(idx) && !filled.contains(idx))
        .count();
    if coverage < min_coverage || new_hits == 0 || triangle_area(tri) < 3.0 {
        return;
    }
    for idx in pixels {
        if mask.contains(&idx) {
            filled.insert(idx);
        }
    }
    let id = *next_cell_id;
    *next_cell_id += 1;
    out.push(PhyleRenderUnit {
        id,
        depth,
        carrier: "HiveCarrier.phyle",
        lean_basis: "Gnosis.SugarbagBeeHive",
        role: role.to_string(),
        render_faces: vec![tri],
        coverage,
    });
}

fn triangle_mask_pixels(tri: [Point; 3], width: u32, height: u32) -> Vec<usize> {
    let x0 = tri
        .iter()
        .map(|p| p.x)
        .fold(f32::INFINITY, f32::min)
        .floor()
        .max(0.0) as u32;
    let y0 = tri
        .iter()
        .map(|p| p.y)
        .fold(f32::INFINITY, f32::min)
        .floor()
        .max(0.0) as u32;
    let x1 = tri
        .iter()
        .map(|p| p.x)
        .fold(f32::NEG_INFINITY, f32::max)
        .ceil()
        .min(width.saturating_sub(1) as f32) as u32;
    let y1 = tri
        .iter()
        .map(|p| p.y)
        .fold(f32::NEG_INFINITY, f32::max)
        .ceil()
        .min(height.saturating_sub(1) as f32) as u32;
    let mut out = Vec::new();
    for y in y0..=y1 {
        for x in x0..=x1 {
            let p = Point {
                x: x as f32 + 0.5,
                y: y as f32 + 0.5,
            };
            if point_in_triangle(p, tri) {
                out.push((y * width + x) as usize);
            }
        }
    }
    out
}

fn frontier_points(
    mask: &HashSet<usize>,
    filled: &HashSet<usize>,
    width: u32,
    bbox: BBox,
) -> Vec<Point> {
    let mut out = Vec::new();
    let stride = 5_u32;
    let mut y = bbox.y0;
    while y <= bbox.y1 {
        let mut x = bbox.x0;
        while x <= bbox.x1 {
            let idx = (y * width + x) as usize;
            if mask.contains(&idx) && !filled.contains(&idx) {
                out.push(Point {
                    x: x as f32,
                    y: y as f32,
                });
            }
            x = x.saturating_add(stride);
            if x == 0 {
                break;
            }
        }
        y = y.saturating_add(stride);
        if y == 0 {
            break;
        }
    }
    out
}

fn nearest_filled_or_base(
    target: Point,
    filled: &HashSet<usize>,
    width: u32,
    base: Point,
) -> Point {
    let mut best = base;
    let mut best_d = distance2(target, base);
    for &idx in filled.iter().take(4096) {
        let p = Point {
            x: (idx as u32 % width) as f32,
            y: (idx as u32 / width) as f32,
        };
        let d = distance2(target, p);
        if d < best_d {
            best = p;
            best_d = d;
        }
    }
    best
}

fn distance2(a: Point, b: Point) -> f32 {
    let dx = a.x - b.x;
    let dy = a.y - b.y;
    dx * dx + dy * dy
}

fn lerp(a: Point, b: Point, t: f32) -> Point {
    Point {
        x: a.x + (b.x - a.x) * t,
        y: a.y + (b.y - a.y) * t,
    }
}

fn triangle_coverage(tri: [Point; 3], mask: &HashSet<usize>, width: u32, height: u32) -> f32 {
    let x0 = tri
        .iter()
        .map(|p| p.x)
        .fold(f32::INFINITY, f32::min)
        .floor()
        .max(0.0) as u32;
    let y0 = tri
        .iter()
        .map(|p| p.y)
        .fold(f32::INFINITY, f32::min)
        .floor()
        .max(0.0) as u32;
    let x1 = tri
        .iter()
        .map(|p| p.x)
        .fold(f32::NEG_INFINITY, f32::max)
        .ceil()
        .min(width.saturating_sub(1) as f32) as u32;
    let y1 = tri
        .iter()
        .map(|p| p.y)
        .fold(f32::NEG_INFINITY, f32::max)
        .ceil()
        .min(height.saturating_sub(1) as f32) as u32;
    let mut inside = 0u32;
    let mut hit = 0u32;
    for y in y0..=y1 {
        for x in x0..=x1 {
            let p = Point {
                x: x as f32 + 0.5,
                y: y as f32 + 0.5,
            };
            if point_in_triangle(p, tri) {
                inside += 1;
                if mask.contains(&((y * width + x) as usize)) {
                    hit += 1;
                }
            }
        }
    }
    if inside == 0 {
        0.0
    } else {
        hit as f32 / inside as f32
    }
}

fn point_in_triangle(p: Point, tri: [Point; 3]) -> bool {
    let d1 = sign(p, tri[0], tri[1]);
    let d2 = sign(p, tri[1], tri[2]);
    let d3 = sign(p, tri[2], tri[0]);
    let has_neg = d1 < 0.0 || d2 < 0.0 || d3 < 0.0;
    let has_pos = d1 > 0.0 || d2 > 0.0 || d3 > 0.0;
    !(has_neg && has_pos)
}

fn sign(p1: Point, p2: Point, p3: Point) -> f32 {
    (p1.x - p3.x) * (p2.y - p3.y) - (p2.x - p3.x) * (p1.y - p3.y)
}

fn triangle_area(tri: [Point; 3]) -> f32 {
    sign(tri[0], tri[1], tri[2]).abs() * 0.5
}

fn render_svg(body: &SolvedBody) -> String {
    let mut s = format!(
        r##"<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 {} {}" width="{}" height="{}">
<rect width="100%" height="100%" fill="#050706"/>
<circle cx="{:.2}" cy="{:.2}" r="5" fill="#b7ff33"/>
<circle cx="{:.2}" cy="{:.2}" r="4" fill="#ffbd4a"/>
"##,
        body.width,
        body.height,
        body.width,
        body.height,
        body.base.x,
        body.base.y,
        body.root.x,
        body.root.y
    );
    for cell in &body.phyle_cells {
        let alpha = (0.20 + cell.coverage * 0.58).min(0.86);
        let hue = match cell.role.as_str() {
            "spine" => 42,
            "left_frond" | "right_frond" => 92 + cell.depth as u32 * 8,
            "recursive_frond" => 118 + cell.depth as u32 * 7,
            _ => 78 + cell.depth as u32 * 11,
        };
        for face in &cell.render_faces {
            s.push_str(&format!(
                r##"<polygon points="{:.2},{:.2} {:.2},{:.2} {:.2},{:.2}" fill="hsl({hue}, 88%, 58%)" fill-opacity="{alpha:.3}" stroke="#101510" stroke-width="0.55"/>
"##,
                face[0].x,
                face[0].y,
                face[1].x,
                face[1].y,
                face[2].x,
                face[2].y
            ));
        }
    }
    s.push_str("</svg>\n");
    s
}

fn render_ply(body: &SolvedBody) -> String {
    let mut points = Vec::new();
    for cell in &body.phyle_cells {
        let (r, g, b) = role_rgb(cell.role.as_str(), cell.depth);
        for face in &cell.render_faces {
            let centroid = Point {
                x: (face[0].x + face[1].x + face[2].x) / 3.0,
                y: (face[0].y + face[1].y + face[2].y) / 3.0,
            };
            for p in [face[0], face[1], face[2], centroid] {
                let x = (p.x / body.width.max(1) as f32) * 2.0 - 1.0;
                let y = 1.0 - (p.y / body.height.max(1) as f32) * 2.0;
                let z = cell.depth as f32 * 0.018 + cell.coverage * 0.035;
                points.push((x, y, z, r, g, b, cell.id, cell.depth, cell.coverage));
            }
        }
    }

    let mut s = format!(
        "ply\nformat ascii 1.0\ncomment source={}\ncomment basis=Gnosis.SugarbagBeeHive carrier=HiveCarrier.phyle\ncomment columns=x y z red green blue phyle_unit depth coverage\nelement vertex {}\nproperty float x\nproperty float y\nproperty float z\nproperty uchar red\nproperty uchar green\nproperty uchar blue\nproperty uint phyle_unit\nproperty uchar depth\nproperty float coverage\nend_header\n",
        body.source,
        points.len()
    );
    for (x, y, z, r, g, b, unit, depth, coverage) in points {
        s.push_str(&format!(
            "{x:.6} {y:.6} {z:.6} {r} {g} {b} {unit} {depth} {coverage:.4}\n"
        ));
    }
    s
}

fn role_rgb(role: &str, depth: u8) -> (u8, u8, u8) {
    let lift = depth.saturating_mul(9).min(72);
    match role {
        "spine" => (215, 190_u8.saturating_add(lift / 3), 44),
        "left_frond" | "right_frond" => (48, 170_u8.saturating_add(lift), 72),
        "recursive_frond" => (34, 210_u8.saturating_add(lift / 2), 126),
        _ => (112, 205_u8.saturating_add(lift / 2), 55),
    }
}
